VALUES
  ('c1111111-1111-1111-1111-111111111111', NULL, 'Dental Implants', 'زراعة الأسنان', 'Permanent solutions for missing teeth with Swiss and German systems.', 'استعد ثقتك بابتسامتك مع زراعة الأسنان السويسرية والألمانية الفورية ثلاثية الأبعاد، حلول دائمة وموثوقة لتعويض الأسنان المفقودة بمظهر طبيعي غاية في الدقة والجمال الطبيعي.', 'Teeth', 'https://images.unsplash.com/photo-1606811841689-23dfddce3e95?q=80&w=800&auto=format&fit=crop', 1, true),
  
  ('c2222222-2222-2222-2222-222222222222', NULL, 'Smile Design', 'تصميم الابتسامة', 'Perfect custom digital smiles tailored to your facial aesthetics.', 'ابتكر ابتسامة هوليوود المتكاملة والرقمية التي تليق بتميزك، مصممة خصيصاً لتتناسب بشكل مثالي مع ملامح وجهك وتمنحك إشراقة طبيعية لا تضاهى.', 'Sparkles', 'https://images.unsplash.com/photo-1522845015757-50bce044e5da?q=80&w=800&auto=format&fit=crop', 2, true),
  
  ('c3333333-3333-3333-3333-333333333333', NULL, 'Teeth Whitening', 'تبييض الأسنان', 'Professional whitening sessions using FLASH and laser technologies.', 'جلسات تبييض احترافية متطورة باستخدام تقنية الفلاش والليزر الآمن لطبقة المينا، تعيد لأسنانك بياضها الطبيعي الناصع وتمنحك بريقاً فورياً جذاباً.', 'Sparkles', 'https://images.unsplash.com/photo-1598256989800-fea5f95ac909?q=80&w=800&auto=format&fit=crop', 3, true),
  
  ('c4444444-4444-4444-4444-444444444444', NULL, 'Cosmetic Dentistry', 'تجميل الأسنان', 'Artistic dental enhancements, gum contouring and fillings.', 'نجمع بين العلم والفن لإبراز جمال ابتسامتك الطبيعية من خلال الحشوات التجميلية المتطورة، وإعادة تشكيل اللثة بالليزر والترميمات الخزفية فائقة الدقة.', 'Sparkles', 'https://images.unsplash.com/photo-1609840114035-3c981b782dfe?q=80&w=800&auto=format&fit=crop', 4, true),
  
  ('c5555555-5555-5555-5555-555555555555', NULL, 'Orthodontics', 'تقويم الأسنان', 'Clear aligners (Invisalign) and modern cosmetic braces.', 'حلول تقويمية متكاملة للكبار والأطفال تشمل التقويم الشفاف (الإنفزلاين) والتقويم الخزفي والعدني، لترتيب وتنظيم اصطفاف أسنانك بشكل متناسق ومثالي.', 'Shield', 'https://images.unsplash.com/photo-1588776814546-1ffcf47267a5?q=80&w=800&auto=format&fit=crop', 5, true),
  
  ('c6666666-6666-6666-6666-666666666666', NULL, 'Veneers', 'عدسات الفينير', 'Handcrafted premium porcelain veneers for flawless smiles.', 'قشور خزفية رقيقة للغاية وعالية المقاومة للتبقع والتآكل، تصنع يدوياً لتقدم لك تحولاً كاملاً وجذاباً للابتسامة بمظهر وملمس طبيعي تماماً.', 'Sparkles', 'https://images.unsplash.com/photo-1512223792601-592a9809eed4?q=80&w=800&auto=format&fit=crop', 6, true);

